471			// Creation is not a transition; the only status write that does not go
472			// through transitionLifecycleInPlace (TD-031 §3 transition matrix).
473			b.Status = DefaultStatus
474		}
475		b.CreatedAt = now
476		b.UpdatedAt = now
477	
478		// Validate after defaults are applied so hooks see final state
