404	// DefaultGitGrep returns a GitGrep hook that runs `git grep -c <symbol>`
405	// inside workingDir. Empty string symbols are rejected.
406	func DefaultGitGrep(workingDir string) func(symbol string) (int, string, error) {
407		return func(symbol string) (int, string, error) {
408			if symbol == "" {
409				return 0, "", fmt.Errorf("empty symbol")
410			}
411			// Use a fixed-string match to avoid regex surprises.
412			cmd := exec.Command("git", "grep", "-c", "-F", "--", symbol)
413			cmd.Dir = workingDir
414			out, _ := cmd.Output() // exit=1 means no match; not an error here
415			hits := 0
416			sample := ""
417			for _, line := range strings.Split(strings.TrimSpace(string(out)), "\n") {
418				if line == "" {
419					continue
420				}
421				// format: "path/file.go:N"
422				parts := strings.SplitN(line, ":", 2)
423				if len(parts) == 2 {
424					// best-effort numeric
425					var n int
426					if _, err := fmt.Sscanf(parts[1], "%d", &n); err == nil {
427						hits += n
428					}
429				}
430				if sample == "" {
431					sample = line
432				}
433			}
434			return hits, sample, nil
435		}
436	}
