84	func (f *CommandFactory) runWorkAnalyze(cmd *cobra.Command, _ []string) error {
85		projectFlag, _ := cmd.Flags().GetString("project")
86		projectRoot := resolveProjectRoot(projectFlag, f.WorkingDir)
87	
88		byDims, _ := cmd.Flags().GetStringSlice("by")
89		sinceStr, _ := cmd.Flags().GetString("since")
90		whereFilters, _ := cmd.Flags().GetStringArray("where")
91		asJSON, _ := cmd.Flags().GetBool("json")
92		asCSV, _ := cmd.Flags().GetBool("csv")
93	
94		for _, d := range byDims {
95			if !analyzeDimValid(d) {
96				return fmt.Errorf("unsupported dimension %q; valid: %s", d, strings.Join(analyzeValidDims, ", "))
97			}
98		}
99	
100		var cutoff time.Time
101		if sinceStr != "" {
102			dur, err := analyzeParseSince(sinceStr)
103			if err != nil {
104				return err
105			}
106			cutoff = time.Now().UTC().Add(-dur)
107		}
108	
109		filters := make(map[string]string)
110		for _, wf := range whereFilters {
111			parts := strings.SplitN(wf, "=", 2)
112			if len(parts) != 2 {
113				return fmt.Errorf("invalid --where %q: expected key=value", wf)
114			}
115			if !analyzeDimValid(parts[0]) {
116				return fmt.Errorf("unsupported --where key %q; valid: %s", parts[0], strings.Join(analyzeValidDims, ", "))
117			}
118			filters[parts[0]] = parts[1]
119		}
120	
121		rows, err := attemptmetrics.LoadRows(projectRoot)
122		if err != nil {
123			return fmt.Errorf("load attempts: %w", err)
124		}
125	
126		aggs := make(map[string]*analyzeAggBucket)
127		var keyOrder []string
128		keyDimVals := make(map[string][]string)
129	
130		for _, r := range rows {
131			if !cutoff.IsZero() && r.TSStart != "" {
132				t, parseErr := time.Parse(time.RFC3339, r.TSStart)
133				if parseErr == nil && t.Before(cutoff) {
134					continue
135				}
136			}
137			match := true
138			for k, v := range filters {
139				if analyzeExtractDim(r, k) != v {
140					match = false
141					break
142				}
143			}
144			if !match {
145				continue
146			}
147	
148			dimVals := make([]string, len(byDims))
149			for i, d := range byDims {
150				dimVals[i] = analyzeExtractDim(r, d)
151			}
152			key := strings.Join(dimVals, "\x00")
153			if _, ok := aggs[key]; !ok {
154				aggs[key] = &analyzeAggBucket{}
155				keyOrder = append(keyOrder, key)
156				keyDimVals[key] = dimVals
157			}
158			agg := aggs[key]
159			agg.count++
160			if r.Outcome == "task_succeeded" {
161				agg.success++
162			}
163			agg.sumCost += r.CostUSD
164			agg.durations = append(agg.durations, r.DurationMS)
165			agg.sumIn += r.InputTokens
166			agg.sumOut += r.OutputTokens
167			if r.Outcome == "review_block" || r.ReviewVerdict == "BLOCK" {
168				agg.blocked++
169			}
170			if r.LadderStepsTaken > 0 {
171				agg.escalated++
172			}
173		}
174	
175		results := make([]analyzeResultRow, 0, len(keyOrder))
176		for _, key := range keyOrder {
177			agg := aggs[key]
178			dimVals := keyDimVals[key]
179			dims := make(map[string]string, len(byDims))
180			for i, d := range byDims {
181				dims[d] = dimVals[i]
182			}
183			results = append(results, analyzeResultRow{
184				Dimensions:      dims,
185				Count:           agg.count,
186				SuccessRate:     analyzeRatio(agg.success, agg.count),
187				AvgCostUSD:      analyzeDiv(agg.sumCost, float64(agg.count)),
188				SumCostUSD:      agg.sumCost,
189				P50DurationMS:   analyzePercentile(agg.durations, 50),
190				P95DurationMS:   analyzePercentile(agg.durations, 95),
191				AvgInputTokens:  analyzeDiv(float64(agg.sumIn), float64(agg.count)),
192				AvgOutputTokens: analyzeDiv(float64(agg.sumOut), float64(agg.count)),
193				ReviewBlockRate: analyzeRatio(agg.blocked, agg.count),
194				EscalationRate:  analyzeRatio(agg.escalated, agg.count),
195			})
196		}
197	
198		out := cmd.OutOrStdout()
199		switch {
200		case asJSON:
201			return analyzeWriteJSONL(out, results)
202		case asCSV:
203			return analyzeWriteCSV(out, byDims, results)
204		default:
205			return analyzeWriteTable(out, byDims, results)
206		}
207	}
