300	func analyzePercentile(vals []int, p int) int {
301		if len(vals) == 0 {
302			return 0
303		}
304		s := make([]int, len(vals))
305		copy(s, vals)
306		sort.Ints(s)
307		idx := p * (len(s) - 1) / 100
308		return s[idx]
309	}
