// lastReviewVerdictFromEvents returns the verdict of the most recent "review"
// event in the slice (APPROVE, BLOCK, etc.), or "" if no review event exists.
func lastReviewVerdictFromEvents(events []BeadEvent) string {
	verdict := ""
	for _, e := range events {
		if e.Kind == "review" {
			verdict = strings.ToUpper(strings.TrimSpace(e.Summary))
		}
	}
	return verdict
}

// Close sets a bead's status to closed. When the close succeeds and the bead
// carries an inline event history, those events are moved to a sidecar
// attachment under .ddx/attachments/<id>/events.jsonl so the active row stays
// small (per ADR-004's attachment model and TD-027 §c).
//
// When the bead had a reviewer verdict of BLOCK, the operator's manual close
// contradicts that verdict; a "review-accuracy-override" event is appended
// so the discrepancy is visible in the audit trail.
func (s *Store) Close(id string) error {
	// Detect prior reviewer BLOCK before closing (best-effort: ignore errors).
	priorVerdict := ""
	if b, err := s.Get(id); err == nil {
		if events, err := s.eventsForBead(b); err == nil {
			priorVerdict = lastReviewVerdictFromEvents(events)
		}
	}
	if err := s.SetLifecycleStatus(id, StatusClosed, LifecycleTransitionOptions{
		ManualClose: true,
		Reason:      "manual close",
		Source:      "Store.Close",
	}); err != nil {
		return err
	}
	if err := s.externalizeEvents(id); err != nil {
		return err
	}
	_ = s.RemoveClaimHeartbeat(id)
	s.maybeOpportunisticMaintenance()
	// Emit review-accuracy-override when operator's close contradicts reviewer BLOCK.
	if priorVerdict == "BLOCK" {
		_ = s.AppendEvent(id, BeadEvent{
			Kind:    "review-accuracy-override",
			Summary: "operator close contradicts reviewer BLOCK",
			Body:    "verdict_was=BLOCK\noperator_action=close\nreason=manual close",
		})
	}
	return nil
}

