// detectACCheckDisagreement compares the reviewer's per-AC grades against the
// mechanical results in acCheckJSON (accheck.Output). Returns the number of
// ACs where the grades disagree (ac-check=fail/reviewer=pass or vice versa)
// and a slice of per-AC reason strings. Only "pass" and "fail" grades are
// compared; "needs_judgment" and "error" mechanical results are skipped.
func detectACCheckDisagreement(acCheckJSON string, perAC []ReviewAC) (int, []string) {
	if acCheckJSON == "" || len(perAC) == 0 {
		return 0, nil
	}
	var out accheck.Output
	if err := json.Unmarshal([]byte(acCheckJSON), &out); err != nil {
		return 0, nil
	}
	mechResult := make(map[int]string, len(out.Items))
	for _, item := range out.Items {
		mechResult[item.AC] = string(item.Result)
	}
	var count int
	var reasons []string
	for _, ac := range perAC {
		mech, ok := mechResult[ac.Number]
		if !ok {
			continue
		}
		if mech != "pass" && mech != "fail" {
			continue // skip needs_judgment / error
		}
		reviewGrade := strings.ToLower(strings.TrimSpace(ac.Grade))
		if (mech == "fail" && reviewGrade == "pass") || (mech == "pass" && reviewGrade == "fail") {
			count++
			reasons = append(reasons, fmt.Sprintf("ac=%d ac-check=%s reviewer=%s", ac.Number, mech, reviewGrade))
		}
	}
	return count, reasons
}

