// Rfc3339 formats a time.Time as RFC3339 UTC; returns "" for the zero value.
func Rfc3339(t time.Time) string {
	if t.IsZero() {
		return ""
	}
	return t.UTC().Format(time.RFC3339)
}

// extractLineValue parses a key=value line from a multi-line body string,
// returning the value for the first matching key, or "" if not found.
func extractLineValue(body, key string) string {
	prefix := key + "="
	for _, line := range strings.Split(body, "\n") {
		if strings.HasPrefix(line, prefix) {
			return strings.TrimSpace(strings.TrimPrefix(line, prefix))
		}
	}
	return ""
}

// parseACOverrideMismatchCount extracts the mismatch_count from a
// review-ac-override event body ("mismatch_count=N" line).
func parseACOverrideMismatchCount(body string) int {
	v := extractLineValue(body, "mismatch_count")
	if v == "" {
		return 0
	}
	n, err := strconv.Atoi(v)
	if err != nil {
		return 0
	}
	return n
}

// parseACOverrideReasons extracts per-AC mismatch lines from a
// review-ac-override event body. Lines starting with "ac=" are reasons.
func parseACOverrideReasons(body string) []string {
	var reasons []string
	for _, line := range strings.Split(body, "\n") {
		line = strings.TrimSpace(line)
		if strings.HasPrefix(line, "ac=") {
			reasons = append(reasons, line)
		}
	}
	return reasons
}

