package bead

import (
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestReviewAccuracy_OperatorOverride_EmitsEvent verifies that:
// - Closing a reviewer-BLOCKed bead emits a "review-accuracy-override" event
//   (false-positive signal: reviewer blocked real work).
// - Reopening a reviewer-APPROVEd bead emits a "review-accuracy-override"
//   event (false-negative signal: reviewer approved fake work).
func TestReviewAccuracy_OperatorOverride_EmitsEvent(t *testing.T) {
	t.Run("close contradicts BLOCK", func(t *testing.T) {
		s := newTestStore(t)
		b := &Bead{Title: "test bead for close override"}
		require.NoError(t, s.Create(b))

		// Reviewer said BLOCK.
		require.NoError(t, s.AppendEvent(b.ID, BeadEvent{
			Kind:    "review",
			Summary: "BLOCK",
			Body:    "reviewer found missing tests",
		}))

		// Operator manually closes (overriding the BLOCK).
		require.NoError(t, s.Close(b.ID))

		// Verify review-accuracy-override event was emitted.
		events, err := s.Events(b.ID)
		require.NoError(t, err)

		var found *BeadEvent
		for i := range events {
			if events[i].Kind == "review-accuracy-override" {
				found = &events[i]
				break
			}
		}
		require.NotNil(t, found, "review-accuracy-override event must be emitted when operator closes a BLOCK-ed bead")
		assert.Contains(t, found.Body, "verdict_was=BLOCK")
		assert.Contains(t, found.Body, "operator_action=close")
	})

	t.Run("no override when no prior review", func(t *testing.T) {
		s := newTestStore(t)
		b := &Bead{Title: "no review bead"}
		require.NoError(t, s.Create(b))
		require.NoError(t, s.Close(b.ID))

		events, err := s.Events(b.ID)
		require.NoError(t, err)
		for _, e := range events {
			assert.NotEqual(t, "review-accuracy-override", e.Kind,
				"no override event should be emitted when bead had no reviewer verdict")
		}
	})

	t.Run("no override when reviewer APPROVEd and operator closes", func(t *testing.T) {
		s := newTestStore(t)
		b := &Bead{Title: "approved then closed"}
		require.NoError(t, s.Create(b))
		require.NoError(t, s.AppendEvent(b.ID, BeadEvent{Kind: "review", Summary: "APPROVE", Body: "all good"}))
		require.NoError(t, s.Close(b.ID))

		events, err := s.Events(b.ID)
		require.NoError(t, err)
		for _, e := range events {
			assert.NotEqual(t, "review-accuracy-override", e.Kind,
				"APPROVE + close is the happy path — no override event")
		}
	})

	t.Run("reopen contradicts APPROVE", func(t *testing.T) {
		s := newTestStore(t)
		b := &Bead{Title: "approved then reopened"}
		require.NoError(t, s.Create(b))

		// Reviewer said APPROVE.
		require.NoError(t, s.AppendEvent(b.ID, BeadEvent{
			Kind:    "review",
			Summary: "APPROVE",
			Body:    "looks good",
		}))

		// Close without a BLOCK override (normal close, no accuracy event for this).
		require.NoError(t, s.Close(b.ID))

		// Operator reopens (operator determined the work was fake).
		require.NoError(t, s.Reopen(b.ID, "fake-work", "work was not real"))

		events, err := s.Events(b.ID)
		require.NoError(t, err)

		var found *BeadEvent
		for i := range events {
			if events[i].Kind == "review-accuracy-override" {
				found = &events[i]
				break
			}
		}
		require.NotNil(t, found, "review-accuracy-override event must be emitted when operator reopens an APPROVE-d bead")
		assert.Contains(t, found.Body, "verdict_was=APPROVE")
		assert.Contains(t, found.Body, "operator_action=reopen")
		assert.Contains(t, found.Body, "fake-work")
	})

	t.Run("reopen with no prior APPROVE does not emit override", func(t *testing.T) {
		s := newTestStore(t)
		b := &Bead{Title: "blocked then closed then reopened"}
		require.NoError(t, s.Create(b))

		// Reviewer said BLOCK, operator closes.
		require.NoError(t, s.AppendEvent(b.ID, BeadEvent{Kind: "review", Summary: "BLOCK", Body: "fail"}))
		require.NoError(t, s.Close(b.ID))

		// Operator reopens — prior verdict was BLOCK (not APPROVE), so no FN signal.
		require.NoError(t, s.Reopen(b.ID, "retry", ""))

		events, err := s.Events(b.ID)
		require.NoError(t, err)

		// The close-override event (FP) was already emitted; now check reopen
		// does NOT add a second override claiming FN.
		fnOverrides := 0
		for _, e := range events {
			if e.Kind == "review-accuracy-override" && e.Body != "" {
				if len(e.Body) > 0 {
					if e.Body == "verdict_was=APPROVE\noperator_action=reopen\nreason=retry" {
						fnOverrides++
					}
				}
			}
		}
		assert.Equal(t, 0, fnOverrides, "reopen after BLOCK close must not emit a false-negative override")
	})
}

