)

// TestReviewAccuracy_ACCheckDisagreement_RecordedInMetrics verifies that:
//   - detectACCheckDisagreement identifies ACs where the reviewer's grade
//     contradicts the mechanical ac-check.json result.
//   - BackfillFromEvents extracts the mismatch count from "review-ac-override"
//     events into the metrics row's ReviewerACMismatchCount field.
func TestReviewAccuracy_ACCheckDisagreement_RecordedInMetrics(t *testing.T) {
	t.Run("detect disagreement: ac-check=fail reviewer=pass", func(t *testing.T) {
		acCheckJSON := `{"schema_version":1,"bead_id":"ddx-test","summary":{"pass":0,"fail":1,"needs_judgment":0,"error":0},"items":[{"ac":1,"kind":"test-name","name":"TestFoo","result":"fail","evidence":"not found in diff"}]}`
		perAC := []ReviewAC{
			{Number: 1, Item: "TestFoo passes", Grade: "pass", Evidence: "TestFoo found in diff"},
		}
		count, reasons := detectACCheckDisagreement(acCheckJSON, perAC)
		assert.Equal(t, 1, count, "ac-check=fail but reviewer=pass is one mismatch")
		require.Len(t, reasons, 1)
		assert.Contains(t, reasons[0], "ac=1")
		assert.Contains(t, reasons[0], "ac-check=fail")
		assert.Contains(t, reasons[0], "reviewer=pass")
	})

	t.Run("detect disagreement: ac-check=pass reviewer=fail", func(t *testing.T) {
		acCheckJSON := `{"schema_version":1,"bead_id":"ddx-test2","summary":{"pass":1,"fail":0,"needs_judgment":0,"error":0},"items":[{"ac":2,"kind":"symbol","name":"Foo","result":"pass","evidence":"Foo found"}]}`
		perAC := []ReviewAC{
			{Number: 2, Item: "Foo symbol present", Grade: "fail", Evidence: "reviewer found Foo missing"},
		}
		count, reasons := detectACCheckDisagreement(acCheckJSON, perAC)
		assert.Equal(t, 1, count)
		require.Len(t, reasons, 1)
		assert.Contains(t, reasons[0], "ac-check=pass")
		assert.Contains(t, reasons[0], "reviewer=fail")
	})

	t.Run("no disagreement when grades agree", func(t *testing.T) {
		acCheckJSON := `{"schema_version":1,"bead_id":"ddx-agree","summary":{"pass":1,"fail":0,"needs_judgment":0,"error":0},"items":[{"ac":1,"kind":"test-name","name":"TestBar","result":"pass","evidence":"found"}]}`
		perAC := []ReviewAC{
			{Number: 1, Item: "TestBar passes", Grade: "pass", Evidence: "confirmed"},
		}
		count, reasons := detectACCheckDisagreement(acCheckJSON, perAC)
		assert.Equal(t, 0, count)
		assert.Empty(t, reasons)
	})

	t.Run("skip needs_judgment in ac-check", func(t *testing.T) {
		acCheckJSON := `{"schema_version":1,"bead_id":"ddx-nj","summary":{"pass":0,"fail":0,"needs_judgment":1,"error":0},"items":[{"ac":1,"kind":"prose","result":"needs_judgment","evidence":"prose AC"}]}`
		perAC := []ReviewAC{
			{Number: 1, Item: "prose AC", Grade: "pass", Evidence: "reviewer adjudicated"},
		}
		count, _ := detectACCheckDisagreement(acCheckJSON, perAC)
		assert.Equal(t, 0, count, "needs_judgment ACs must not be flagged as disagreements")
	})

	t.Run("BackfillFromEvents extracts mismatch count into metrics row", func(t *testing.T) {
		projectRoot := t.TempDir()
		now := time.Now().UTC()

		beadEvents := []attemptmetrics.BeadAttemptEvents{
			{
				BeadID: "ddx-backfill-test",
				Events: []bead.BeadEvent{
					{
						Kind:      "cost",
						Body:      `{"attempt_id":"attempt-acc-1","model":"test-model","harness":"claude","cost_usd":0.01,"duration_ms":1000,"input_tokens":100,"output_tokens":50}`,
						CreatedAt: now,
					},
					{
						Kind:      "execute-bead",
						Summary:   "task_succeeded",
						CreatedAt: now,
					},
					{
						Kind:      "review",
						Body:      "verdict: APPROVE\nmodel=reviewer-model-X\ninput_bytes=500\noutput_bytes=200\nelapsed_ms=800",
						Summary:   "APPROVE",
						CreatedAt: now,
					},
					{
						Kind:      "review-ac-override",
						Summary:   "1 AC(s) disagree with ac-check.json",
						Body:      "mismatch_count=1\nac=1 ac-check=fail reviewer=pass",
						CreatedAt: now,
					},
				},
			},
		}

		added, err := attemptmetrics.BackfillFromEvents(projectRoot, beadEvents)
		require.NoError(t, err)
		assert.Equal(t, 1, added)

		rows, err := attemptmetrics.LoadRows(projectRoot)
		require.NoError(t, err)
		require.Len(t, rows, 1)

		row := rows[0]
		assert.Equal(t, "attempt-acc-1", row.AttemptID)
		assert.Equal(t, 1, row.ReviewerACMismatchCount,
			"BackfillFromEvents must extract mismatch_count from review-ac-override event")
		assert.Equal(t, "reviewer-model-X", row.ReviewerModel,
			"BackfillFromEvents must extract reviewer model from review event body")
		assert.Len(t, row.ReviewerOverrideReasons, 1)
		assert.Contains(t, row.ReviewerOverrideReasons[0], "ac=1")
	})

	t.Run("BackfillFromEvents records accuracy_signal=override from review-accuracy-override", func(t *testing.T) {
		projectRoot := t.TempDir()
		now := time.Now().UTC()

		beadEvents := []attemptmetrics.BeadAttemptEvents{
			{
				BeadID: "ddx-accuracy-signal-test",
				Events: []bead.BeadEvent{
					{
						Kind:      "cost",
						Body:      `{"attempt_id":"attempt-sig-1","model":"test-model","cost_usd":0.01,"duration_ms":500}`,
						CreatedAt: now,
					},
					{
						Kind:      "execute-bead",
						Summary:   "task_succeeded",
						CreatedAt: now,
					},
					{
						Kind:      "review",
						Summary:   "APPROVE",
						Body:      "APPROVE\nmodel=reviewer-Y\ninput_bytes=100\noutput_bytes=50\nelapsed_ms=400",
						CreatedAt: now,
					},
					{
						Kind:      "review-accuracy-override",
						Summary:   "operator reopen contradicts reviewer APPROVE",
						Body:      "verdict_was=APPROVE\noperator_action=reopen\nreason=fake-work",
						CreatedAt: now,
					},
				},
			},
		}

		added, err := attemptmetrics.BackfillFromEvents(projectRoot, beadEvents)
		require.NoError(t, err)
		assert.Equal(t, 1, added)

		rows, err := attemptmetrics.LoadRows(projectRoot)
		require.NoError(t, err)
		require.Len(t, rows, 1)
		assert.Equal(t, "override", rows[0].ReviewerAccuracySignal,
			"BackfillFromEvents must set ReviewerAccuracySignal=override from review-accuracy-override event")
	})
}

