// TestAnalyze_ByReviewerModel_SurfacesFPRate verifies that `ddx work analyze
// --by reviewer-model` is a valid grouping dimension and that the
// reviewer_fp_rate and reviewer_fn_rate columns are computed correctly from
// ReviewVerdict and ReviewerAccuracySignal fields.
func TestAnalyze_ByReviewerModel_SurfacesFPRate(t *testing.T) {
	dir := t.TempDir()
	writeAnalyzeRows(t, dir, []attemptmetrics.AttemptRow{
		// reviewer-A: 2 BLOCK verdicts, 1 is a false-positive (override).
		{SchemaVersion: 1, AttemptID: "r1", BeadID: "b1", ReviewerModel: "reviewer-A",
			ReviewVerdict: "BLOCK", ReviewerAccuracySignal: "override",
			Outcome: "review_block", DurationMS: 1000},
		{SchemaVersion: 1, AttemptID: "r2", BeadID: "b2", ReviewerModel: "reviewer-A",
			ReviewVerdict: "BLOCK", ReviewerAccuracySignal: "",
			Outcome: "review_block", DurationMS: 1200},
		// reviewer-B: 1 APPROVE verdict that is a false-negative (override).
		{SchemaVersion: 1, AttemptID: "r3", BeadID: "b3", ReviewerModel: "reviewer-B",
			ReviewVerdict: "APPROVE", ReviewerAccuracySignal: "override",
			Outcome: "task_succeeded", DurationMS: 800},
		// reviewer-B: 1 confirmed APPROVE (no override).
		{SchemaVersion: 1, AttemptID: "r4", BeadID: "b4", ReviewerModel: "reviewer-B",
			ReviewVerdict: "APPROVE", ReviewerAccuracySignal: "",
			Outcome: "task_succeeded", DurationMS: 900},
	})

	out := runAnalyze(t, dir, "--by", "reviewer-model")

	// Both reviewer models should appear in the output.
	if !strings.Contains(out, "reviewer-A") {
		t.Errorf("expected reviewer-A in output, got: %s", out)
	}
	if !strings.Contains(out, "reviewer-B") {
		t.Errorf("expected reviewer-B in output, got: %s", out)
	}

	// FP/FN rate columns must be present in the header.
	if !strings.Contains(out, "reviewer_fp_rate") {
		t.Errorf("expected reviewer_fp_rate column in output, got: %s", out)
	}
	if !strings.Contains(out, "reviewer_fn_rate") {
		t.Errorf("expected reviewer_fn_rate column in output, got: %s", out)
	}

	// Verify correct FP/FN rates using JSON output for precision.
	jsonOut := runAnalyze(t, dir, "--by", "reviewer-model", "--json")
	lines := strings.Split(strings.TrimSpace(jsonOut), "\n")
	if len(lines) != 2 {
		t.Fatalf("expected 2 JSON rows (one per reviewer-model), got %d: %s", len(lines), jsonOut)
	}

	type resultRow struct {
		Dimensions     map[string]string `json:"dimensions"`
		ReviewerFPRate float64           `json:"reviewer_fp_rate"`
		ReviewerFNRate float64           `json:"reviewer_fn_rate"`
	}
	var rows []resultRow
	for _, line := range lines {
		var r resultRow
		if err := json.Unmarshal([]byte(line), &r); err != nil {
			t.Fatalf("unmarshal JSON row: %v", err)
		}
		rows = append(rows, r)
	}

	// Find reviewer-A and reviewer-B rows.
	var rowA, rowB *resultRow
	for i := range rows {
		switch rows[i].Dimensions["reviewer-model"] {
		case "reviewer-A":
			rowA = &rows[i]
		case "reviewer-B":
			rowB = &rows[i]
		}
	}
	require.NotNil(t, rowA, "reviewer-A row must appear in JSON output")
	require.NotNil(t, rowB, "reviewer-B row must appear in JSON output")

	// reviewer-A: FP rate = 1 FP override / 2 BLOCK total = 0.5
	if rowA.ReviewerFPRate < 0.49 || rowA.ReviewerFPRate > 0.51 {
		t.Errorf("reviewer-A FP rate = %.4f, want ~0.5", rowA.ReviewerFPRate)
	}
	// reviewer-A: no APPROVE verdicts, so FN rate = 0
	if rowA.ReviewerFNRate != 0 {
		t.Errorf("reviewer-A FN rate = %.4f, want 0.0", rowA.ReviewerFNRate)
	}

	// reviewer-B: no BLOCK verdicts, so FP rate = 0
	if rowB.ReviewerFPRate != 0 {
		t.Errorf("reviewer-B FP rate = %.4f, want 0.0", rowB.ReviewerFPRate)
	}
	// reviewer-B: FN rate = 1 FN override / 2 APPROVE total = 0.5
	if rowB.ReviewerFNRate < 0.49 || rowB.ReviewerFNRate > 0.51 {
		t.Errorf("reviewer-B FN rate = %.4f, want ~0.5", rowB.ReviewerFNRate)
	}
}

